"use strict";(self.webpackChunkwp_wallet_system_doc=self.webpackChunkwp_wallet_system_doc||[]).push([[3851],{5478(t,e,a){a.r(e),a.d(e,{comp:()=>l,data:()=>s});var d=a(641);const r={class:"hint-container tip"},o={},l=(0,a(6262).A)(o,[["render",function(t,e){const a=(0,d.g2)("RouteLink");return(0,d.uX)(),(0,d.CE)("div",null,[e[8]||(e[8]=(0,d.Lk)("h1",{id:"cashback-engine",tabindex:"-1"},[(0,d.Lk)("a",{class:"header-anchor",href:"#cashback-engine"},[(0,d.Lk)("span",null,"Cashback Engine")])],-1)),e[9]||(e[9]=(0,d.Lk)("p",null,"Reward customers automatically on every order. Drives repeat purchase by parking the reward in their wallet — they spend it next time.",-1)),(0,d.Lk)("div",r,[e[3]||(e[3]=(0,d.Lk)("p",{class:"hint-container-title"},"Setting up?",-1)),(0,d.Lk)("p",null,[e[1]||(e[1]=(0,d.eW)("Skip to ",-1)),(0,d.Lk)("strong",null,[(0,d.bF)(a,{to:"/admin-settings/cashback.html"},{default:(0,d.k6)(()=>[...e[0]||(e[0]=[(0,d.eW)("Cashback Settings",-1)])]),_:1})]),e[2]||(e[2]=(0,d.eW)(" for the step-by-step rule-editor walkthrough + 5 ready-to-use recipes.",-1))])]),e[10]||(e[10]=(0,d.Fv)('<h2 id="what-it-does" tabindex="-1"><a class="header-anchor" href="#what-it-does"><span>What It Does</span></a></h2><table><thead><tr><th>For</th><th>Means</th></tr></thead><tbody><tr><td><strong>Customer</strong></td><td>Earn wallet credit automatically on completed orders. Spend it on the next purchase</td></tr><tr><td><strong>Admin</strong></td><td>Build rules in the admin UI — by product, category, or store-wide. Pick percent or fixed amount. Set caps</td></tr></tbody></table><h2 id="how-customers-see-it" tabindex="-1"><a class="header-anchor" href="#how-customers-see-it"><span>How Customers See It</span></a></h2><ol><li>Place an order → pay → order completes</li><li>Wallet gets credited automatically</li><li>Activity feed shows a <code>Cashback</code> row with the rule name + amount</li><li>Cashback email fires (if enabled)</li></ol><p>That&#39;s it. No coupon codes, no claim flow.</p><p><img src="/wp-wallet-system/images/mywallet-activity.webp" alt="Recent activity card — cashback rows show inline alongside top-up, refund, transfer"></p><h2 id="rule-anatomy" tabindex="-1"><a class="header-anchor" href="#rule-anatomy"><span>Rule Anatomy</span></a></h2><p><strong>Wallet → Cashback Rules → Add new</strong></p><p><img src="/wp-wallet-system/images/admin-cashback-rules.webp" alt="Cashback Rules list — priority, scope, type, status; click any row to edit"></p><table><thead><tr><th>Field</th><th>What it does</th></tr></thead><tbody><tr><td>Name</td><td>internal label (also shown in customer activity feed)</td></tr><tr><td>Active</td><td>rule fires only when ON</td></tr><tr><td>Scope</td><td><code>product</code> / <code>category</code> / <code>global</code></td></tr><tr><td>Targets</td><td>the products / categories — only when scope is product/category</td></tr><tr><td>Match</td><td><code>OR</code> (any line item matches) / <code>AND</code> (all line items match)</td></tr><tr><td>Min order value</td><td>rule fires only above this cart total</td></tr><tr><td>Max order value</td><td>optional ceiling</td></tr><tr><td>Type</td><td><code>percent</code> / <code>fixed</code></td></tr><tr><td>Amount</td><td>the percent (e.g. <code>5</code> = 5%) or currency value</td></tr><tr><td>Max cashback cap</td><td>optional per-order ceiling</td></tr><tr><td>Priority</td><td>lower runs first; first matching rule wins</td></tr><tr><td>Start / End date</td><td>optional window</td></tr><tr><td>Per-customer cap</td><td>max times this rule can fire for one customer</td></tr></tbody></table><div class="hint-container tip"><p class="hint-container-title">One cashback per order</p><p>The engine awards <strong>one</strong> cashback per order — whichever rule matches first by priority. To stack multiple percentages, build a single rule that combines them.</p></div><h2 id="common-setups" tabindex="-1"><a class="header-anchor" href="#common-setups"><span>Common Setups</span></a></h2><h3 id="_5-on-everything-no-minimum" tabindex="-1"><a class="header-anchor" href="#_5-on-everything-no-minimum"><span>5% on everything, no minimum</span></a></h3><table><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Scope</td><td>global</td></tr><tr><td>Min order value</td><td>0</td></tr><tr><td>Type</td><td>percent</td></tr><tr><td>Amount</td><td>5</td></tr></tbody></table><p>Simplest possible rule. Drives wallet engagement across the catalogue.</p><h3 id="_10-only-on-electronics-min-order-₹2000-capped-at-₹1000" tabindex="-1"><a class="header-anchor" href="#_10-only-on-electronics-min-order-₹2000-capped-at-₹1000"><span>10% only on Electronics, min order ₹2000, capped at ₹1000</span></a></h3><table><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Scope</td><td>category</td></tr><tr><td>Targets</td><td>Electronics</td></tr><tr><td>Min order value</td><td>2000</td></tr><tr><td>Type</td><td>percent</td></tr><tr><td>Amount</td><td>10</td></tr><tr><td>Max cap</td><td>1000</td></tr></tbody></table><p>Higher-margin categories get more aggressive cashback.</p><h3 id="flat-₹50-cashback-on-the-launch-sku" tabindex="-1"><a class="header-anchor" href="#flat-₹50-cashback-on-the-launch-sku"><span>Flat ₹50 cashback on the launch SKU</span></a></h3><table><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Scope</td><td>product</td></tr><tr><td>Targets</td><td>LAUNCH-SKU-1</td></tr><tr><td>Type</td><td>fixed</td></tr><tr><td>Amount</td><td>50</td></tr></tbody></table><p>Drives attention to a specific product.</p><h3 id="limited-time-double-cashback" tabindex="-1"><a class="header-anchor" href="#limited-time-double-cashback"><span>Limited-time double cashback</span></a></h3><p>Build two rules:</p><ul><li>Rule A: priority <code>10</code>, scope global, percent <code>5</code> (your baseline)</li><li>Rule B: priority <code>5</code>, scope global, percent <code>10</code>, with <code>start_date</code> + <code>end_date</code> set to the campaign window</li></ul><p>During the window Rule B (lower priority = checked first) wins. After the window, only Rule A matches.</p><h2 id="refund-reversal" tabindex="-1"><a class="header-anchor" href="#refund-reversal"><span>Refund Reversal</span></a></h2><p>When the order is refunded, cashback reverses automatically.</p><table><thead><tr><th>Refund</th><th>Cashback</th></tr></thead><tbody><tr><td>Full refund</td><td>full cashback debited</td></tr><tr><td>Partial refund</td><td>proportional cashback debited</td></tr><tr><td>Order cancelled</td><td>no reversal — cashback applies on <code>completed</code>, not <code>processing</code></td></tr></tbody></table><p>Reversal is protected — never debits below zero. If the customer has spent the cashback already, the shortfall becomes BNPL debt (only when BNPL is enabled).</p><h2 id="settings-that-affect-this" tabindex="-1"><a class="header-anchor" href="#settings-that-affect-this"><span>Settings That Affect This</span></a></h2><table><thead><tr><th>Setting</th><th>Where</th><th>Effect</th></tr></thead><tbody><tr><td>Cashback basis</td><td>filterable</td><td>subtotal-ex-tax (default), subtotal-inc-tax, or total</td></tr><tr><td>Cashback email</td><td>Notifications tab</td><td>toggle the credited-confirmation email</td></tr></tbody></table><h2 id="when-something-goes-wrong" tabindex="-1"><a class="header-anchor" href="#when-something-goes-wrong"><span>When Something Goes Wrong</span></a></h2><table><thead><tr><th>Problem</th><th>Fix</th></tr></thead><tbody><tr><td>Cashback not credited</td><td>Rule active? Min met? Order in <code>completed</code>? Already credited?</td></tr><tr><td>Wrong rule fired</td><td>Check priority — lower number runs first</td></tr><tr><td>Cashback credited twice</td><td>Should not happen — guard meta on order. Delete the duplicate ledger row + open a ticket</td></tr><tr><td>Want cashback on subtotal but it&#39;s on total</td><td>Use the <code>wkwp_cashback_basis</code> filter (see dev section)</td></tr></tbody></table><details class="hint-container details"><summary>For developers — hooks + idempotency</summary><h3 id="resolution-flow" tabindex="-1"><a class="header-anchor" href="#resolution-flow"><span>Resolution flow</span></a></h3><p><code>WKWP_Cashback_Engine::resolve_for_order</code>:</p><ol><li>Load all active rules ordered by <code>priority ASC</code></li><li>For each rule, check date window, scope, min/max order value, per-customer cap</li><li>First rule passing all checks → compute amount → break</li></ol><h3 id="idempotency" tabindex="-1"><a class="header-anchor" href="#idempotency"><span>Idempotency</span></a></h3><p>Order meta <code>_wkwp_cashback_processed = yes</code> written immediately after credit. Subsequent runs of <code>woocommerce_order_status_completed</code> (admin flipping statuses) are no-ops.</p><p>To re-issue cashback (rare): delete the meta + the matching ledger row, then re-trigger order status.</p><h3 id="hooks" tabindex="-1"><a class="header-anchor" href="#hooks"><span>Hooks</span></a></h3><table><thead><tr><th>Hook</th><th>Type</th><th>When</th></tr></thead><tbody><tr><td><code>wkwp_cashback_eligible_rules</code></td><td>filter</td><td>mutate the rules list before resolution</td></tr><tr><td><code>wkwp_cashback_resolved_rule</code></td><td>filter</td><td>swap out the chosen rule</td></tr><tr><td><code>wkwp_cashback_amount</code></td><td>filter</td><td>mutate computed cashback before credit</td></tr><tr><td><code>wkwp_cashback_credited</code></td><td>action</td><td>after credit row written</td></tr><tr><td><code>wkwp_cashback_reversed</code></td><td>action</td><td>after refund reversal</td></tr><tr><td><code>wkwp_cashback_basis</code></td><td>filter</td><td><code>subtotal_ex_tax</code> / <code>subtotal_inc_tax</code> / <code>total</code></td></tr></tbody></table><h3 id="reporting" tabindex="-1"><a class="header-anchor" href="#reporting"><span>Reporting</span></a></h3><p>Filter Wallet → Transactions by <code>type = cashback</code>. CSV export for accounting reconciliation.</p></details><h2 id="related" tabindex="-1"><a class="header-anchor" href="#related"><span>Related</span></a></h2>',35)),(0,d.Lk)("ul",null,[(0,d.Lk)("li",null,[(0,d.bF)(a,{to:"/core-wallet.html"},{default:(0,d.k6)(()=>[...e[4]||(e[4]=[(0,d.eW)("Core Wallet",-1)])]),_:1})]),(0,d.Lk)("li",null,[(0,d.bF)(a,{to:"/refund-to-wallet.html"},{default:(0,d.k6)(()=>[...e[5]||(e[5]=[(0,d.eW)("Refund to Wallet",-1)])]),_:1})]),(0,d.Lk)("li",null,[(0,d.bF)(a,{to:"/daily-login-reward.html"},{default:(0,d.k6)(()=>[...e[6]||(e[6]=[(0,d.eW)("Daily Login Reward",-1)])]),_:1})]),(0,d.Lk)("li",null,[(0,d.bF)(a,{to:"/filters-hooks.html"},{default:(0,d.k6)(()=>[...e[7]||(e[7]=[(0,d.eW)("Filters & Hooks",-1)])]),_:1})])])])}]]),s=JSON.parse('{"path":"/cashback.html","title":"Cashback Engine","lang":"en-US","frontmatter":{"title":"Cashback Engine","description":"Reward customers automatically on every order. Per-product, per-category, or store-wide rules. Percent or fixed amount.","meta":[{"name":"keywords","content":"woocommerce cashback, wallet cashback, cashback rule engine, percent cashback, fixed cashback, cashback per category"}]},"headers":[{"level":2,"title":"What It Does","slug":"what-it-does","link":"#what-it-does","children":[]},{"level":2,"title":"How Customers See It","slug":"how-customers-see-it","link":"#how-customers-see-it","children":[]},{"level":2,"title":"Rule Anatomy","slug":"rule-anatomy","link":"#rule-anatomy","children":[]},{"level":2,"title":"Common Setups","slug":"common-setups","link":"#common-setups","children":[{"level":3,"title":"5% on everything, no minimum","slug":"_5-on-everything-no-minimum","link":"#_5-on-everything-no-minimum","children":[]},{"level":3,"title":"10% only on Electronics, min order ₹2000, capped at ₹1000","slug":"_10-only-on-electronics-min-order-₹2000-capped-at-₹1000","link":"#_10-only-on-electronics-min-order-₹2000-capped-at-₹1000","children":[]},{"level":3,"title":"Flat ₹50 cashback on the launch SKU","slug":"flat-₹50-cashback-on-the-launch-sku","link":"#flat-₹50-cashback-on-the-launch-sku","children":[]},{"level":3,"title":"Limited-time double cashback","slug":"limited-time-double-cashback","link":"#limited-time-double-cashback","children":[]}]},{"level":2,"title":"Refund Reversal","slug":"refund-reversal","link":"#refund-reversal","children":[]},{"level":2,"title":"Settings That Affect This","slug":"settings-that-affect-this","link":"#settings-that-affect-this","children":[]},{"level":2,"title":"When Something Goes Wrong","slug":"when-something-goes-wrong","link":"#when-something-goes-wrong","children":[]},{"level":2,"title":"Related","slug":"related","link":"#related","children":[]}],"git":{},"filePathRelative":"cashback.md"}')}}]);